def findCheapestPrice(n, flights, src, dst, k):
    import collections
    adj = collections.defaultdict(list)
    for u, v, w in flights: adj[u].append((v, w))
    prices = {src: 0}
    q = collections.deque([(src, 0, 0)])
    while q:
        node, cost, stops = q.popleft()
        if stops > k: continue
        for v, w in adj[node]:
            if v not in prices or prices[v] > cost + w:
                prices[v] = cost + w
                q.append((v, cost + w, stops + 1))
    return prices.get(dst, -1)

